                  v-else
                  :disabled="row.disabledExpand"
                  v-bind="{ ...ui.default.expandButton || {}, ...expandButton }"
                  :ui="{ icon: { base: [ui.expand.icon, isExpanded(row) && 'rotate-180'].join(' ') } }"
                  @click.capture.stop="toggleOpened(row)"
                />
